        const CONFIG = {
            bubbleInterval: 400,
            bubbleSizeMin: 20, 
            bubbleSizeMax: 90,
            bubbleDurationMin: 10, 
            bubbleDurationMax: 18,
            // 适配浅色背景的气泡颜色
            bubbleColors: [
                'rgba(244, 114, 182, 0.7)', // 主粉色
