<!DOCTYPE html>
<html lang="zh-CN">
  <head>
    <meta charset="UTF-8" />
    <style>
      /* 复古RPG/日系冒险面板样式 */
      .rpg-panel-container {
        width: 100%;
        max-width: 90%;
        margin: 10px auto;
        border-radius: 6px;
        background: #F3E8D6; /* 羊皮纸/米色底 */
        border: 2px solid #D8C8B0;
        box-shadow: 2px 2px 6px rgba(0,0,0,0.08);
        font-family: 'Microsoft YaHei', 'PingFang SC', sans-serif;
        color: #3D352A;
        overflow: hidden;
      }
      .rpg-panel-header {
        padding: 10px 14px;
        font-size: 0.92em;
        font-weight: bold;
        background: #EBDAB8;
        border-bottom: 2px solid #D8C8B0;
        text-align: center;
        letter-spacing: 1px;
        color: #5C4A3D;
      }
      .rpg-option-list {
        padding: 12px;
        display: flex;
        flex-direction: column;
        gap: 8px;
      }
      .rpg-option-item {
        background: #FFFDF9; /* 按钮稍亮 */
        border: 1px solid #E3D5C5;
        border-radius: 4px;
        padding: 10px 14px 10px 32px;
        cursor: pointer;
        position: relative;
        transition: all 0.2s ease;
        font-size: 0.95em;
        line-height: 1.4;
        user-select: none;
      }
      /* 去除Emoji，使用指定符号 */
      .rpg-option-item::before {
        content: '>';
        position: absolute;
        left: 12px;
        color: #B59B6D;
        font-weight: bold;
        font-family: monospace;
        transition: transform 0.2s;
      }
      .rpg-option-item:hover {
        background: #FDF6EB;
        border-color: #C2A878;
        transform: translateX(4px);
        box-shadow: 1px 1px 4px rgba(0,0,0,0.05);
      }
      .rpg-option-item:hover::before {
        transform: translateX(3px) scale(1.1);
      }
      .rpg-option-item:active {
        transform: translateX(4px) scale(0.99);
        background: #DFCDA6;
      }
    </style>
  </head>
  <body>
    <!-- 带有未处理标识的容器 -->
    <div class="rpg-panel-container rpg-unprocessed">
      <div class="rpg-panel-header">行动选项</div>
      <!-- 正则提取的内容注入于此 -->
      <div class="rpg-raw-data" style="display:none;">$1</div>
      <!-- 动态生成的列表 -->
      <div class="rpg-option-list"></div>
    </div>

    <script>
      (function() {
        const processOptions = () => {
          // 查找所有还没有被解析成按钮的面板
          const panels = document.querySelectorAll('.rpg-panel-container.rpg-unprocessed');
          panels.forEach(panel => {
            panel.classList.remove('rpg-unprocessed');
            const rawDataEl = panel.querySelector('.rpg-raw-data');
            const listEl = panel.querySelector('.rpg-option-list');

            if (!rawDataEl || !listEl) return;

            // 【核心修复1】：SillyTavern 会把原文里的换行变成 <br> 或 <p>
            // 我们必须获取 innerHTML，然后手动把 <br> 和 </p> 替换回系统的换行符
            let htmlContent = rawDataEl.innerHTML;
            htmlContent = htmlContent.replace(/<br\s*\/?>/gi, String.fromCharCode(10));
            htmlContent = htmlContent.replace(/<\/p>/gi, String.fromCharCode(10));
            // 剔除剩余的所有杂乱HTML标签（比如加粗、斜体等被误伤的格式）
            htmlContent = htmlContent.replace(/<[^>]+>/g, '');

            // 现在可以安全地按换行符切分了
            const lines = htmlContent.split(String.fromCharCode(10));

            lines.forEach(line => {
              let text = line.trim();

              // 自动剥离类似 "1："、"2." 等数字前缀
              text = text.replace(/^\d+[\:：\.\、]\s*/, '');
              // 自动剥离两端的 【】 或 []
              text = text.replace(/^[【\[]/, '').replace(/[】\]]$/, '');
              text = text.trim();

              if (!text) return;

              // 动态创建符合 RPG 样式的条目
              const btn = document.createElement('div');
              btn.className = 'rpg-option-item';
              btn.textContent = text;

              // 绑定点击事件，内容送入输入框
              btn.addEventListener('click', () => {
                try {
                  const doc = window.parent.document || document;
                  const input = doc.querySelector('#send_textarea'); 
                  if (input) {
                    const currentVal = input.value.trim();
                    // 追加内容并加上换行符
                    input.value = currentVal ? currentVal + String.fromCharCode(10) + text : text;
                    // 触发SillyTavern的输入检测
                    input.dispatchEvent(new Event('input', { bubbles: true }));
                  }
                } catch (err) {
                  console.error('发送到输入框失败:', err);
                }
              });

              listEl.appendChild(btn);
            });
          });
        };

        // 立即执行一次解析
        processOptions();

        // 【核心修复2】：轮询补救措施。
        // ST的某些渲染插件会让DOM元素慢半拍才加载出来。
        // 这里设定一个循环，每200毫秒扫描一次，扫描10次后停止，确保不管它什么时候加载出来都能100%命中抓取。
        let ticks = 0;
        const timer = setInterval(() => {
          processOptions();
          ticks++;
          if (ticks > 10) clearInterval(timer);
        }, 200);
      })();
    </script>
  </body>
</html>
